parameters.jsCode:
const lease = $('PDF Vector - Analyze Lease').item.json.data || $('PDF Vector - Analyze Lease').item.json;
const advice = $input.first().json.answer || $input.first().json.markdown || '';
const fileName = $('Google Drive Trigger').item.json.name;

const monthlyRent = parseFloat(lease.monthlyRent) || 0;
const securityDeposit = parseFloat(lease.securityDeposit) || 0;
const petDeposit = parseFloat(lease.petDeposit) || 0;
const moveInCost = monthlyRent + securityDeposit + petDeposit;

const landlordInfo = [lease.landlordName, lease.landlordCompany].filter(Boolean).join(' (').replace(/(.+)/, '$1)').replace(/^(.+)\)$/, '$1') || 'Not specified';

let petSummary = 'Not specified';
if (lease.petsAllowed === true) {
  petSummary = 'Allowed';
  if (petDeposit) petSummary += ` - Deposit: $${petDeposit}`;
  if (lease.petRent) petSummary += `, Monthly: $${lease.petRent}`;
  if (lease.petRestrictions) petSummary += ` (${lease.petRestrictions})`;
} else if (lease.petsAllowed === false) { petSummary = 'Not allowed'; }

const lateFee = lease.latePaymentFee
  ? `$${lease.latePaymentFee} after ${lease.latePaymentGracePeriod || 0} days`
  : 'Not specified';

const highFlags = (lease.highRedFlags || '').split(';').map(f => f.trim()).filter(Boolean);
const medFlags  = (lease.mediumRedFlags || '').split(';').map(f => f.trim()).filter(Boolean);
const lowFlags  = (lease.lowRedFlags || '').split(';').map(f => f.trim()).filter(Boolean);
const allFlags  = [
  ...highFlags.map(f => `[High] ${f}`),
  ...medFlags.map(f  => `[Medium] ${f}`),
  ...lowFlags.map(f  => `[Low] ${f}`)
];
const flagsSummary = allFlags.join('; ') || 'None identified';

let riskLevel = 'Low';
if (highFlags.length >= 2) riskLevel = 'High';
else if (highFlags.length === 1 || allFlags.length >= 3) riskLevel = 'Medium';

const adviceShort = advice && advice.length > 500 ? advice.substring(0, 500) + '...' : advice;

return [{ json: {
  propertyAddress:  lease.propertyAddress  || 'Not specified',
  landlord:         landlordInfo,
  tenants:          lease.tenantNames       || 'Not specified',
  monthlyRent,
  securityDeposit,
  moveInCost,
  leaseStart:       lease.leaseStart        || 'Not specified',
  leaseEnd:         lease.leaseEnd          || 'Not specified',
  leaseTerm:        lease.leaseTerm         || 'Not specified',
  autoRenewal:      lease.autoRenewal ? 'Yes' : 'No',
  petPolicy:        petSummary,
  utilities:        lease.utilitiesIncluded || 'None included',
  lateFee,
  earlyTermination: lease.earlyTerminationPenalty || 'Not specified',
  moveOutNotice:    lease.moveOutNotice ? `${lease.moveOutNotice} days` : 'Not specified',
  flagsSummary,
  riskLevel,
  tenantAdvice:      advice,
  tenantAdviceShort: adviceShort,
  fileName,
  fileId: $('Google Drive Trigger').item.json.id,
  processedAt: new Date().toISOString()
}}];

